#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define HASH_SIZE 100000
#define MAX_KMER_LEN 64
#define MAX_CONTIG_LEN 10000

typedef struct kmer_node {
    char kmer[MAX_KMER_LEN];
    char left_ext;
    char right_ext;
    bool visited;
    struct kmer_node* next;
} kmer_node_t;

typedef struct {
    kmer_node_t* table[HASH_SIZE];
} hash_table_t;

// Hash function for k-mer strings
unsigned int hash(const char* kmer) {
    unsigned int hash_val = 5381;
    while (*kmer) {
        hash_val = ((hash_val << 5) + hash_val) + *kmer;
        kmer++;
    }
    return hash_val % HASH_SIZE;
}

// Initialize hash table
hash_table_t* init_hash_table() {
    hash_table_t* ht = malloc(sizeof(hash_table_t));
    for (int i = 0; i < HASH_SIZE; i++) {
        ht->table[i] = NULL;
    }
    return ht;
}

// Insert k-mer into hash table
void insert_kmer(hash_table_t* ht, const char* kmer, char left_ext, char right_ext) {
    unsigned int index = hash(kmer);

    // Check if kmer already exists
    kmer_node_t* current = ht->table[index];
    while (current) {
        if (strcmp(current->kmer, kmer) == 0) {
            return; // Already exists
        }
        current = current->next;
    }

    // Create new node
    kmer_node_t* new_node = malloc(sizeof(kmer_node_t));
    strcpy(new_node->kmer, kmer);
    new_node->left_ext = left_ext;
    new_node->right_ext = right_ext;
    new_node->visited = false;
    new_node->next = ht->table[index];
    ht->table[index] = new_node;
}

// Find k-mer in hash table
kmer_node_t* find_kmer(hash_table_t* ht, const char* kmer) {
    unsigned int index = hash(kmer);
    kmer_node_t* current = ht->table[index];

    while (current) {
        if (strcmp(current->kmer, kmer) == 0) {
            return current;
        }
        current = current->next;
    }
    return NULL;
}

// Get next k-mer by extending to the right
void get_next_kmer(const char* current_kmer, char ext, char* next_kmer) {
    int len = strlen(current_kmer);
    strncpy(next_kmer, current_kmer + 1, len - 1);
    next_kmer[len - 1] = ext;
    next_kmer[len] = '\0';
}

// Get previous k-mer by extending to the left
void get_prev_kmer(const char* current_kmer, char ext, char* prev_kmer) {
    int len = strlen(current_kmer);
    prev_kmer[0] = ext;
    strncpy(prev_kmer + 1, current_kmer, len - 1);
    prev_kmer[len] = '\0';
}

// Traverse graph to build contigs
void build_contigs(hash_table_t* ht, FILE* output) {
    for (int i = 0; i < HASH_SIZE; i++) {
        kmer_node_t* current = ht->table[i];

        while (current) {
            if (!current->visited) {
                // Start building a contig from this k-mer
                char contig[MAX_CONTIG_LEN];
                int contig_len = 0;

                // First, go backward as much as possible to find the start
                char start_kmer[MAX_KMER_LEN];
                strcpy(start_kmer, current->kmer);
                kmer_node_t* start_node = current;

                while (start_node->left_ext != 'F') {
                    char prev_kmer[MAX_KMER_LEN];
                    get_prev_kmer(start_kmer, start_node->left_ext, prev_kmer);
                    kmer_node_t* prev_node = find_kmer(ht, prev_kmer);

                    if (!prev_node || prev_node->visited || prev_node->right_ext == 'F') {
                        break;
                    }

                    // Check if this forms a valid extension
                    char expected_next[MAX_KMER_LEN];
                    get_next_kmer(prev_kmer, prev_node->right_ext, expected_next);
                    if (strcmp(expected_next, start_kmer) != 0) {
                        break;
                    }

                    strcpy(start_kmer, prev_kmer);
                    start_node = prev_node;
                }

                // Now build the contig forward from the start
                strcpy(contig, start_kmer);
                contig_len = strlen(start_kmer);
                start_node->visited = true;

                char current_kmer[MAX_KMER_LEN];
                strcpy(current_kmer, start_kmer);
                kmer_node_t* current_node = start_node;

                while (current_node->right_ext != 'F' && contig_len < MAX_CONTIG_LEN - 1) {
                    char next_kmer[MAX_KMER_LEN];
                    get_next_kmer(current_kmer, current_node->right_ext, next_kmer);
                    kmer_node_t* next_node = find_kmer(ht, next_kmer);

                    if (!next_node || next_node->visited) {
                        break;
                    }

                    // Check if this forms a valid extension
                    char expected_prev[MAX_KMER_LEN];
                    get_prev_kmer(next_kmer, next_node->left_ext, expected_prev);
                    if (strcmp(expected_prev, current_kmer) != 0 && next_node->left_ext != 'F') {
                        break;
                    }

                    // Extend the contig
                    contig[contig_len++] = current_node->right_ext;
                    contig[contig_len] = '\0';

                    strcpy(current_kmer, next_kmer);
                    current_node = next_node;
                    current_node->visited = true;
                }

                // Output the contig if it's significant
                if (contig_len > 0) {
                    fprintf(output, "%s\n", contig);
                }
            }
            current = current->next;
        }
    }
}

int main(int argc, char* argv[]) {
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <input_file>\n", argv[0]);
        return 1;
    }

    FILE* input = fopen(argv[1], "r");
    if (!input) {
        fprintf(stderr, "Error opening input file: %s\n", argv[1]);
        return 1;
    }

    FILE* output = fopen("/app/serial.out", "w");
    if (!output) {
        fprintf(stderr, "Error opening output file\n");
        fclose(input);
        return 1;
    }

    hash_table_t* ht = init_hash_table();

    char line[256];
    while (fgets(line, sizeof(line), input)) {
        // Remove newline
        line[strcspn(line, "\n")] = '\0';

        // Parse the line: kmer\tleft_ext right_ext
        char* tab_pos = strchr(line, '\t');
        if (!tab_pos || strlen(tab_pos) < 3) {
            continue;
        }

        *tab_pos = '\0';
        char* kmer = line;
        char left_ext = tab_pos[1];
        char right_ext = tab_pos[2];

        insert_kmer(ht, kmer, left_ext, right_ext);
    }

    build_contigs(ht, output);

    fclose(input);
    fclose(output);

    // Free memory
    for (int i = 0; i < HASH_SIZE; i++) {
        kmer_node_t* current = ht->table[i];
        while (current) {
            kmer_node_t* temp = current;
            current = current->next;
            free(temp);
        }
    }
    free(ht);

    return 0;
}
